 "patefeuilletee": {
  "nom": "Puff Pastry",
  "description": "True homemade puff pastry — crispy, buttery, and flaky. Quantities for 1 to 5 pastries (mold ~28 cm).",
  "etapes": [
   {
    "titre": "The Dough",
    "detail": "Mix the flour and salt. Add cold water a little at a time until forming a supple ball, without overworking. Score a cross on top, wrap in plastic, and refrigerate."
   },
   {
    "titre": "The Butter Block",
    "detail": "Place cold butter between two sheets of parchment paper and flatten it with a rolling pin into a regular square about 1 cm thick. CHEF'S TIP: the butter should have the same consistency as the dough—neither too hard nor too soft—otherwise it will break through the layers during lamination."
   },
   {
    "titre": "Encasing the Butter",
    "detail": "Roll out the dough into a cross shape, place the butter square in the center, and fold the four flaps over it to enclose it completely, like an envelope."
   },
   {
    "titre": "First Double Turn",
    "detail": "Roll into a long, even rectangle, then fold into thirds (both ends toward the center, then fold in half). Wrap in plastic and refrigerate."
   },
   {
    "titre": "Second Double Turn",
    "detail": "Rotate the dough a quarter turn, roll out into a rectangle again, and fold into thirds. Wrap in plastic and refrigerate."
   },
   {
    "titre": "Third Double Turn",
    "detail": "Repeat one final time with a quarter turn, rolling, and folding into thirds. Three double turns total: this final rest sets the lamination."
   },
   {
    "titre": "Rolling and Storage",
    "detail": "Roll to the desired thickness, ready to line or cut. It keeps for 3 days in the refrigerator, or 3 months in the freezer well wrapped."
   }
  ]
 },
