 "painperdubrioche": {
  "nom": "Brioche French Toast",
  "description": "Brioche French Toast — the ultimate anti-waste brunch star. Slices of day-old brioche dipped in an egg-milk-vanilla custard, golden in butter, caramelized with sugar. Served with maple syrup, fresh fruit, or vanilla cream.",
  "etapes": [
   {
    "titre": "Choose Your Bread",
    "detail": "CHEF'S TIP: French toast = day-old bread, at least 1-2 days old. Day-old brioche is the TOP choice (fluffy + sweet). Otherwise: thick white bread, sliced baguette, brioche loaf. The older the bread, the better it absorbs the custard."
   },
   {
    "titre": "Slice the Bread",
    "detail": "Cut into THICK SLICES, 2-3cm each. The thicker the slice, the more custardy the center (otherwise it dries out)."
   },
   {
    "titre": "Prepare the Custard",
    "detail": "In a shallow dish, whisk vigorously: 3 whole eggs + 250ml whole milk + 50g sugar + 1 teaspoon vanilla extract (or the seeds from 1/2 vanilla bean) + 1 pinch of cinnamon. Add 1 tablespoon of rum or Grand Marnier (optional for adults)."
   },
   {
    "titre": "Dip the Slices",
    "detail": "Dip each slice in the custard mixture: 15-20 SECONDS per side (no more, or it falls apart). Must be soaked but still HOLD its shape. CHEF'S TIP: remove gently with a spatula."
   },
   {
    "titre": "Heat the Pan",
    "detail": "Large non-stick or cast iron skillet. Heat over MEDIUM heat (not too high = burns outside, raw inside). Melt 30g butter + 1 tablespoon oil (the oil prevents the butter from burning)."
   },
   {
    "titre": "Cook the Slices",
    "detail": "Cook each slice 2-3 minutes per side until GOLDEN and CRISPY. Don't overcrowd the pan (leave space between slices). Add more butter between batches if needed."
   },
   {
    "titre": "Caramelize (Chef's Technique)",
    "detail": "PRO TECHNIQUE: sprinkle each slice with brown sugar or muscovado sugar at the end of cooking. Let sit 30 seconds: the sugar melts and caramelizes = divine crispy crust."
   },
   {
    "titre": "Prepare the Toppings",
    "detail": "Your choice: fresh fruit (strawberries, raspberries, bananas), maple syrup, honey, powdered sugar, Nutella, fruit compote, whipped cream, vanilla ice cream for a dessert version."
   },
   {
    "titre": "Brunch Service",
    "detail": "Serve IMMEDIATELY (otherwise it gets soggy). Stack 2-3 slices per plate. DRIZZLE with maple syrup, top with fresh fruit. Beverages: black coffee, Earl Grey tea, fresh orange juice. Perfect Sunday brunch!"
   }
  ]
 },
